private viewContainer = inject(ViewContainerRef);

// Refrencing Template using queries
alertTemplate = viewChild<TemplateRef<any>>('alert');
showAlert(): void {
  this.viewContainer.createEmbeddedView(this.alertTemplate() as TemplateRef<any>);
}

