// Subject
const sub1 = new Subject<number>();
sub1.next(1); // This value will not be received by any subscribers because there are no subscribers at this point.
sub1.subscribe(value => console.log('Subscriber 1:', value));
sub1.next(2); //Subscriber 1: 2
sub1.subscribe(value => console.log('Subscriber 2:', value));
sub1.next(3); //Subscriber 1: 3, Subscriber 2: 3

// Behavior Subject
const behaviorSub = new BehaviorSubject<number>(0);
const subs1 = behaviorSub.subscribe(value => console.log('Behavior Subscriber 1:', value)); //Behavior Subscriber 1: 0
behaviorSub.next(1); //Behavior Subscriber 1: 1
subs1.unsubscribe();
behaviorSub.subscribe(value => console.log('Behavior Subscriber 2:', value)); //Behavior Subscriber 2: 1

// Replay Subject
const replaySub = new ReplaySubject<number>(2);
replaySub.next(1);
replaySub.subscribe(value => console.log('Replay Subscriber 1:', value)); //Replay Subscriber 1: 1
replaySub.next(2); //Replay Subscriber 1: 2
replaySub.next(3); // Replay Subscriber 1: 3
replaySub.subscribe(value => console.log('Replay Subscriber 2:', value));//Replay Subscriber 2: 2, Replay Subscriber 2: 3
replaySub.next(4); // Replay Subscriber 1: 4, Replay Subscriber 2: 4

