//Exhaust Map
refreshEvent$ = new BehaviorSubject(0);

ngOnInit(): void {
  this.refreshEvent$.pipe(
    exhaustMap((count) => this.refreshAPI(count))
  ).subscribe(x => console.log(x));
}

refreshClick(): void {
  const val = this.refreshEvent$.value + 1;
  console.log("Refresh content: ", val);
  this.refreshEvent$.next(val);
}

refreshAPI(count: number): Observable<any> {
  return new Observable((obs) => {
    setTimeout(() => {
      obs.next(`Refreshed content for ${count}`)
      obs.complete()
    }, 3000);
  });
}

