/** combineLatest(): It emits an array/object containing latest value 
 * from each observable once all source emits at least one value, 
 * then onwards it emits the updated array if any source emits.
 */

balance$ = new Observable<number>();
private getCurrencyRate$ = new BehaviorSubject(90);
private getBalance$ = new BehaviorSubject(1000);

ngOnInit(): void {
  this.balance$ = combineLatest([
    this.getBalance$,
    this.getCurrencyRate$
  ]).pipe(
    map(([bal, rate])=> bal*rate)
  );
}

