/**
 * concat(): It subscribes to Observables one after another 
 * in sequence and emits all values from the current Observable
 * before subscribing to the next one. 
 * 
 * It maintains order and does not interleave emissions.
 */

private name$ = of('Aman', 'Ram', 'Joy');
private age$ = interval(3000).pipe(take(3));

concat(
  this.age$,
  this.name$,
).subscribe(val => console.log(val));

//Console Output
0
1
2
//It will wait 3sec to fetch, then triggers 2nd observable
Aman
Ram
Joy

/**
 * merge(): Combines multiple Observables into a single 
 * output Observable that emits values from all merged 
 * Observables concurrently, as they occur. 
 * 
 * Doesn't maintains order.
 */

private name$ = of('Aman', 'Ram', 'Joy');
private age$ = interval(3000).pipe(take(3));

merge(
  this.age$,
  this.name$,
).subscribe(val => console.log(val));

//Console Output
//It won't wait for 1st observable to get finished
Aman
Ram
Joy
0
1
2

/**
 * zip(): Combines values from multiple Observables 
 * by pairing them in sequence (the first value of A 
 * with the first value of B). It emits a combined array 
 * of paired results only when all source Observables 
 * have emitted a value for the current index. 
 * 
 * If ObsA emits but ObsB doesn't, then zip won't emit any value.
 */

private name$ = of('Aman', 'Ram', 'Joy');
private age$ = interval(3000).pipe(take(3));

zip(
  this.age$,
  this.name$,
).subscribe(val => console.log(val));

//Console Output
[0, 'Aman']
[1, 'Ram']
[2, 'Joy']

